SELECT prediction_id, symbol
FROM predictions
WHERE symbol = 'BTC';

SELECT AVG(confidence) AS average_confidence
FROM sentiment_analysis
WHERE timestamp BETWEEN '2018-07-11 00:00:00' AND '2018-07-11 23:59:59';

SELECT u.username, p.symbol
FROM users u
JOIN predictions p ON u.user_id = p.prediction_id;

SELECT text, timestamp
FROM tweets
WHERE sentiment = 'bullish';

SELECT * 
FROM anomaly_detection 
WHERE severity = 'high' AND symbol = 'BTC';

SELECT model_name, ASINH(model_accuracy) AS model_accuracy
FROM machine_learning_models
WHERE model_id = 0;

SELECT timestamp 
FROM exchange_data
WHERE symbol = 'BTC' AND volume_btc > 100000;

SELECT timestamp, log_level, log_message, log_code
FROM logs
WHERE log_message LIKE '%your_username_here%';

SELECT sentiment 
FROM news_articles 
WHERE article_id = 0;

SELECT COUNT(tweet_id) AS tweet_count
FROM tweets
WHERE timestamp BETWEEN datetime('now', '-7 days') AND datetime('now');
